-- Optimized iso_build prompt: compressed schema example + deduplication rule
UPDATE dna_app.ai_prompts SET prompt_text = E'You are a compliance documentation expert. You will receive the full text of an ISO standard.\n\nYour task is to produce:\n1. A concise SUMMARY of the standard\n2. A complete set of OPERATIONAL PROCEDURE TEMPLATES — each one is a REAL DOCUMENT with placeholder gaps\n\nSTRICT RULES:\n- Use ONLY content from the provided ISO text. Do not add, invent, or interpret.\n- Preserve original ISO clause and control IDs exactly (e.g. 4.1, A.5.1, 8.2.3)\n- Every organization-specific value MUST become a {{placeholder_key}} embedded directly in the document text\n- Use lowercase_underscore for placeholder keys (e.g. {{organization_name}}, {{ciso_role}})\n- Group related controls into logical standalone procedure documents\n- Each fillable section MUST include its ISO reference (clause or control ID)\n\nDOCUMENT STRUCTURE REQUIREMENT:\n- fixed_sections contain the actual document text with {{placeholders}} embedded inline\n- fillable_sections describe each unique placeholder — one entry per unique placeholder key\n- The "placeholder" field MUST exactly match a {{key}} used in fixed_sections content\n- Every fillable_section MUST have a "question" field\n\nFILLABLE_SECTIONS DEDUPLICATION RULE (CRITICAL FOR OUTPUT SIZE):\n- Common placeholders (e.g. {{organization_name}}, {{ciso_role}}) appear in MANY templates\n- Define each placeholder FULLY only in the FIRST template where it appears\n- In subsequent templates, OMIT fillable_sections entries for placeholders already defined in earlier templates\n- Only include NEW placeholders unique to that template in its fillable_sections\n- This is mandatory — repeating the same placeholder across all templates wastes tokens\n\nPLACEHOLDER CONVENTION:\n- {{organization_name}} — legal name of the organization\n- {{ciso_role}} — person responsible for information security\n- {{relevant_role}} — other responsible person/team\n- {{system_name}} — specific system or application\n- {{evidence_record}} — evidence or record to be maintained\n- {{risk_id}} — risk register reference\n- Add domain-specific placeholders as needed\n\nQUESTION FIELD RULES:\n- Complete natural-language question a consultant would ask the customer\n- Specific enough that the answer directly fills the placeholder\n- Examples: {{organization_name}} -> "What is the full legal name of your organization?"\n\nAUTOMATION HOOKS (required on every fillable_section):\n- "automation_source": "hr_system"|"asset_inventory"|"risk_register"|"ad_directory"|"manual"|"scan_tool"|"ticketing_system"\n- "auto_fillable": true/false\n- "trigger_event": "employee_onboarding"|"system_change"|"annual_review"|"incident"|"audit"\n\nReturn ONLY valid JSON:\n{\n  "summary": {"standard_name":"...","overview":"...","total_clauses":0,"total_controls":0,"key_themes":[],"document_count":0},\n  "templates": [\n    {\n      "name": "ISMS 01 ...",\n      "covered_clauses": ["4.1"],\n      "covered_controls": ["A.5.1"],\n      "fixed_sections": [\n        {"id":"purpose","title":"Purpose","content":"This policy applies to {{organization_name}} under {{ciso_role}}.","section_type":"policy_statement","iso_reference":"5.1"}\n      ],\n      "fillable_sections": [\n        {"id":"org_name","title":"Organization Name","location":"Purpose","type":"text","semantic_tags":["organization"],"placeholder":"{{organization_name}}","question":"What is the full legal name of your organization?","is_required":true,"is_mandatory":true,"iso_reference":"4.1","iso_control_title":"...","automation_source":"hr_system","auto_fillable":true,"trigger_event":"annual_review"}\n      ]\n    }\n  ]\n}\n\nISO STANDARD TEXT:\n{{ISO_TEXT}}\n'
WHERE prompt_key = 'iso_build';

-- Optimized iso_build_formal prompt: same deduplication + compressed schema
UPDATE dna_app.ai_prompts SET prompt_text = E'You are a compliance documentation expert. You will receive the full text of an ISO standard.\n\nYour task is to produce:\n1. A concise SUMMARY of the standard\n2. A complete set of FORMAL ISMS PROCEDURE DOCUMENTS in the formal ISMS format\n\nSTRICT RULES:\n- Use ONLY content from the provided ISO text. Do not add, invent, or interpret.\n- Preserve original ISO clause and control IDs exactly (e.g. 4.1, A.5.1, 8.2.3)\n- Every organization-specific value MUST become a {{placeholder_key}} embedded directly in the document text\n- Use lowercase_underscore for placeholder keys\n- Group related controls into logical standalone procedure documents\n\nDOCUMENT STRUCTURE REQUIREMENT:\n- sections array: first two entries MUST be document_control_table and approval_table\n- Numbered sections: 1=Purpose, 2=Scope, 3=Normative References, 4=Terms, 5=Context, 6=Procedures (subsections 6.1-6.9), 7=Responsibilities, 8=Related Documents, 9=Revision History, 10=Exceptions, 11=Enforcement\n- Section 6 MUST use subsections array, each with id, number, title, content, iso_reference\n- appendix MUST be present with type annex_a_table\n- fillable_sections: one entry per unique placeholder key appearing in sections/appendix\n- Every fillable_section MUST have a "question" field\n- Document control placeholders (document_title, document_id, version, effective_date, review_date, document_owner, classification, prepared_by, reviewed_by, approved_by) MUST appear in fillable_sections\n\nFILLABLE_SECTIONS DEDUPLICATION RULE (CRITICAL FOR OUTPUT SIZE):\n- Define each placeholder FULLY only in the FIRST template where it appears\n- In subsequent templates, OMIT fillable_sections entries for placeholders already defined in earlier templates\n- Only include NEW placeholders unique to that template\n- This is mandatory — repeating the same placeholder across all templates wastes tokens\n\nPLACEHOLDER CONVENTION:\n- {{organization_name}}, {{ciso_role}}, {{relevant_role}}, {{system_name}}, {{evidence_record}}, {{risk_id}}\n- {{document_title}}, {{document_id}}, {{version}}, {{effective_date}}, {{review_date}}, {{document_owner}}, {{classification}}\n- {{prepared_by}}, {{reviewed_by}}, {{approved_by}} and their _date variants\n\nQUESTION FIELD RULES:\n- Complete natural-language question a consultant would ask the customer\n- Specific enough that the answer directly fills the placeholder\n\nAUTOMATION HOOKS (required on every fillable_section):\n- "automation_source": "hr_system"|"asset_inventory"|"risk_register"|"ad_directory"|"manual"|"scan_tool"|"ticketing_system"\n- "auto_fillable": true/false\n- "trigger_event": "employee_onboarding"|"system_change"|"annual_review"|"incident"|"audit"\n\nReturn ONLY valid JSON:\n{\n  "summary": {"standard_name":"...","overview":"...","total_clauses":0,"total_controls":0,"key_themes":[],"document_count":0},\n  "templates": [\n    {\n      "name": "ISMS 01 ...",\n      "covered_clauses": ["4.1"],\n      "covered_controls": ["A.5.1"],\n      "template_format": "formal",\n      "sections": [\n        {"id":"doc_control","title":"Document Control","type":"document_control_table","fields":{"document_title":"{{document_title}}","document_id":"{{document_id}}","version":"{{version}}","effective_date":"{{effective_date}}","review_date":"{{review_date}}","owner":"{{document_owner}}","classification":"{{classification}}"}},\n        {"id":"doc_approval","title":"Document Approval","type":"approval_table","rows":[{"role":"Prepared by","name":"{{prepared_by}}","date":"{{prepared_date}}"},{"role":"Reviewed by","name":"{{reviewed_by}}","date":"{{reviewed_date}}"},{"role":"Approved by","name":"{{approved_by}}","date":"{{approved_date}}"}]},\n        {"id":"s1","number":"1","title":"Purpose","type":"numbered_section","content":"This policy applies to {{organization_name}}.","iso_reference":"5.1"},\n        {"id":"s6","number":"6","title":"Procedures","type":"numbered_section","subsections":[{"id":"s6_1","number":"6.1","title":"Risk Assessment","content":"{{organization_name}} shall conduct risk assessments.","iso_reference":"6.1.2"}]}\n      ],\n      "appendix": {"title":"Appendix A — Annex A Control Mapping","type":"annex_a_table","rows":[{"control_id":"A.5.1","control_title":"...","section_ref":"1","status":"Implemented"}]},\n      "fillable_sections": [\n        {"id":"org_name","title":"Organization Name","location":"Section 1","type":"text","semantic_tags":["organization"],"placeholder":"{{organization_name}}","question":"What is the full legal name of your organization?","is_required":true,"is_mandatory":true,"iso_reference":"4.1","iso_control_title":"...","automation_source":"hr_system","auto_fillable":true,"trigger_event":"annual_review"}\n      ]\n    }\n  ]\n}\n\nISO STANDARD TEXT:\n{{ISO_TEXT}}\n'
WHERE prompt_key = 'iso_build_formal';
